func hasRole(actor Role, required Role) bool {
	return roleRank[actor] >= roleRank[required]
}

func parseDurationOrZero(s string) (time.Duration, error) {
	s = strings.TrimSpace(s)
	if s == "" || s == "0" || strings.EqualFold(s, "perm") || strings.EqualFold(s, "permanent") {
		return 0, nil
	}
	return time.ParseDuration(s)
}

func splitCommandLine(line string) []string {
	line = strings.TrimSpace(line)
	if line == "" {
		return nil
	}
	var out []string
	var cur strings.Builder
	inQuote := false
	esc := false
	for _, r := range line {
		if esc {
			cur.WriteRune(r)
			esc = false
			continue
		}
		switch r {
		case '\\':
			esc = true
		case '"':
			inQuote = !inQuote
		case ' ', '\t':
			if inQuote {
				cur.WriteRune(r)
			} else if cur.Len() > 0 {
				out = append(out, cur.String())
				cur.Reset()
			}
		default:
			cur.WriteRune(r)
		}
	}
	if cur.Len() > 0 {
		out = append(out, cur.String())
	}
	return out
}

func parseGiveItemsArgs(args []string) (map[string]int, error) {
	items := make(map[string]int)
	for _, a := range args {
		a = strings.TrimSpace(a)
		if a == "" {
			continue
		}
		parts := strings.SplitN(a, ":", 2)
		if len(parts) != 2 {
			return nil, fmt.Errorf("invalid item spec %q (expected item:qty)", a)
		}
		item := strings.TrimSpace(parts[0])
		if item == "" {
			return nil, fmt.Errorf("invalid item name in %q", a)
		}
		qty, err := strconv.Atoi(strings.TrimSpace(parts[1]))
		if err != nil {
			return nil, fmt.Errorf("invalid qty in %q: %w", a, err)
		}
		items[item] += qty
	}
	if len(items) == 0 {
		return nil, errors.New("no items specified")
	}
	return items, nil
}

func newID() string {
	var b [16]byte
	_, _ = rand.Read(b[:])
	return hex.EncodeToString(b[:])
}

func remoteIP(addr string) string {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return addr
	}
	return host
}

