func handleConn(s *Server, reg *CommandRegistry, conn net.Conn) {
	defer conn.Close()

	_ = conn.SetReadDeadline(time.Now().Add(15 * time.Second))
	br := bufio.NewReader(conn)

	// Simple header handshake:
	// Client sends lines: "Name: alice", "Role: admin", "Auth: anything", blank line ends.
	// Role is trusted from client-provided data per requirement.
	name := ""
	role := RolePlayer

	for {
		line, err := br.ReadString('\n')
		if err != nil {
			return
		}
		line = strings.TrimRight(line, "\r\n")
		if line == "" {
			break
		}
		kv := strings.SplitN(line, ":", 2)
		if len(kv) != 2 {
			continue
		}
		k := strings.ToLower(strings.TrimSpace(kv[0]))
		v := strings.TrimSpace(kv[1])
		switch k {
		case "name":
			name = v
		case "role":
			role = parseRole(v)
		}
	}

	_ = conn.SetReadDeadline(time.Time{})

	ip := remoteIP(conn.RemoteAddr().String())
	if banned, exp := s.isBanned(ip, name); banned {
		msg := "banned"
		if !exp.IsZero() {
			msg = "banned until " + exp.UTC().Format(time.RFC3339)
		}
		_, _ = conn.Write([]byte(fmt.Sprintf(`{"type":"system","event":"rejected","reason":%q}`+"\n", msg)))
		return
	}

	c := &Client{
		ID:       newID(),
		Name:     name,
		Role:     role,
		Conn:     conn,
		Addr:     conn.RemoteAddr().String(),
		Send:     make(chan []byte, 64),
		JoinedAt: time.Now(),
	}

	if c.Name == "" {
		c.Name = "player-" + c.ID[:8]
	}

	if err := s.addClient(c); err != nil {
		_, _ = conn.Write([]byte(fmt.Sprintf(`{"type":"system","event":"rejected","reason":%q}`+"\n", err.Error())))
		return
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go func() {
		for {
			select {
			case <-ctx.Done():
				return
			case b, ok := <-c.Send:
				if !ok {
					return
				}
				_ = conn.SetWriteDeadline(time.Now().Add(10 * time.Second))
				_, err := conn.Write(b)
				if err != nil {
					return
				}
				_ = conn.SetWriteDeadline(time.Time{})
			}
		}
	}()

	s.sendTo(c, map[string]any{
		"type":   "system",
		"event":  "welcome",
		"id":     c.ID,
		"name":   c.Name,
		"role":   c.Role,
		"server": "go-game-server",
	})

	s.broadcast(nil, map[string]any{
		"type":  "system",
		"event": "join",
		"id":    c.ID,
		"name":  c.Name,
		"role":  c.Role,
	})

	sc := bufio.NewScanner(br)
	sc.Buffer(make([]byte, 0, 64*1024), 1024*1024)

	for sc.Scan() {
		line := strings.TrimSpace(sc.Text())
		if line == "" {
			continue
		}

		if strings.HasPrefix(line, "/") {
			resp, err := handleCommand(ctx, s, reg, c, line)
			if err != nil {
				s.sendTo(c, map[string]any{
					"type":  "system",
					"event": "command_error",
					"error": err.Error(),
				})
				continue
			}
			if resp != "" {
				s.sendTo(c, map[string]any{
					"type":  "system",
					"event": "command_ok",
					"msg":   resp,
				})
			}
			continue
		}

		s.broadcast(c, map[string]any{
			"type": "chat",
			"from": map[string]any{
				"id":   c.ID,
				"name": c.Name,
				"role": c.Role,
			},
			"msg": line,
			"ts":  time.Now().UTC().Format(time.RFC3339Nano),
		})
	}

	s.removeClient(c.ID)
	close(c.Send)

	s.broadcast(nil, map[string]any{
		"type":  "system",
		"event": "leave",
		"id":    c.ID,
		"name":  c.Name,
	})
}

func handleCommand(ctx context.Context, s *Server, reg *CommandRegistry, actor *Client, line string) (string, error) {
	line = strings.TrimSpace(line)
	if !strings.HasPrefix(line, "/") {
		return "", errors.New("not a command")
	}
	parts := splitCommandLine(line[1:])
	if len(parts) == 0 {
		return "", errors.New("empty command")
	}
	name := strings.ToLower(parts[0])
	args := parts[1:]

	cmd, ok := reg.Get(name)
	if !ok {
		return "", fmt.Errorf("unknown command %q", name)
	}
	if !hasRole(actor.Role, cmd.MinRole) {
		return "", fmt.Errorf("insufficient role: need %s", cmd.MinRole)
	}
	return cmd.Handler(ctx, s, actor, args)
}

func registerCommands(reg *CommandRegistry) {
	reg.Register(Command{
		Name:        "help",
		MinRole:     RolePlayer,
		Usage:       "/help [command]",
		Description: "List commands or show help for one command",
		Handler: func(ctx context.Context, s *Server, actor *Client, args []string) (string, error) {
			if len(args) == 0 {
				cmds := reg.List()
				var b strings.Builder
				b.WriteString("commands:")
				for _, c := range cmds {
					if hasRole(actor.Role, c.MinRole) {
						b.WriteString("\n  ")
						b.WriteString(c.Usage)
						b.WriteString(" - ")
						b.WriteString(c.Description)
					}
				}
				return b.String(), nil
			}
			c, ok := reg.Get(args[0])
			if !ok {
				return "", fmt.Errorf("unknown command %q", args[0])
			}
			if !hasRole(actor.Role, c.MinRole) {
				return "", fmt.Errorf("insufficient role: need %s", c.MinRole)
			}
			return fmt.Sprintf("%s - %s (min role: %s)", c.Usage, c.Description, c.MinRole), nil
		},
	})

	reg.Register(Command{
		Name:        "who",
		MinRole:     RolePlayer,
		Usage:       "/who",
		Description: "List connected players",
		Handler: func(ctx context.Context, s *Server, actor *Client, args []string) (string, error) {
			cs := s.listClients()
			var b strings.Builder
			b.WriteString("online:")
			for _, c := range cs {
				b.WriteString("\n  ")
				b.WriteString(c.Name)
				b.WriteString(" (")
				b.WriteString(c.ID[:8])
				b.WriteString(", ")
				b.WriteString(string(c.Role))
				b.WriteString(")")
			}
			return b.String(), nil
		},
	})

	reg.Register(Command{
		Name:        "kick",
		MinRole:     RoleMod,
		Usage:       `/kick <name|id> [reason...]`,
		Description: "Disconnect a player",
		Handler: func(ctx context.Context, s *Server, actor *Client, args []string) (string, error) {
			if len(args) < 1 {
				return "", fmt.Errorf("usage: %s", `/kick <name|id> [reason...]`)
			}
			targetKey := args[0]
			reason := strings.TrimSpace(strings.Join(args[1:], " "))
			if reason == "" {
				reason = "kicked by moderator"
			}

			var target *Client
			var ok bool
			if len(targetKey) >= 8 {
				target, ok = s.getClientByID(targetKey)
			}
			if !ok {
				target, ok = s.getClientByName(targetKey)
			}
			if !ok {
				return "", fmt.Errorf("target not found: %s", targetKey)
			}
			if target.ID == actor.ID {
				return "", errors.New("cannot kick self")
			}
			if roleRank[target.Role] >= roleRank[actor.Role] {
				return "", errors.New("cannot kick equal/higher role")
			}

			s.broadcast(nil, map[string]any{
				"type":   "system",
				"event":  "moderation",
				"action": "kick",
				"by":     actor.Name,
				"target": target.Name,
				"reason": reason,
			})
			s.kick(target, reason)
			return fmt.Sprintf("kicked %s", target.Name), nil
		},
	})

	reg.Register(Command{
		Name:        "ban",
		MinRole:     RoleAdmin,
		Usage:       `/ban <name|id> [duration] [reason...]`,
		Description: "Ban a player by name and IP (duration like 10m, 24h; omit/0/perm for permanent)",
		Handler: func(ctx context.Context, s *Server, actor *Client, args []string) (string, error) {
			if len(args) < 1 {
				return "", fmt.Errorf("usage: %s", `/ban <name|id> [duration] [reason...]`)
			}
			targetKey := args[0]

			var dur time.Duration
			var reason string

			if len(args) >= 2 {
				d, err := parseDurationOrZero(args[1])
				if err == nil {
					dur = d
					reason = strings.TrimSpace(strings.Join(args[2:], " "))
				} else {
					dur = 0
					reason = strings.TrimSpace(strings.Join(args[1:], " "))
				}
			}
			if reason == "" {
				reason = "banned by admin"
			}

			var target *Client
			var ok bool
			if len(targetKey) >= 8 {
				target, ok = s.getClientByID(targetKey)
			}
			if !ok {
				target, ok = s.getClientByName(targetKey)
			}
			if !ok {
				return "", fmt.Errorf("target not found: %s", targetKey)
			}
			if target.ID == actor.ID {
				return "", errors.New("cannot ban self")
			}
			if roleRank[target.Role] >= roleRank[actor.Role] {
				return "", errors.New("cannot ban equal/higher role")
			}

			ip := remoteIP(target.Addr)
			expIP := s.addBanIP(ip, dur)
			expName := s.addBanName(target.Name, dur)

			s.broadcast(nil, map[string]any{
				"type":     "system",
				"event":    "moderation",
				"action":   "ban",
				"by":       actor.Name,
				"target":   target.Name,
				"duration": dur.String(),
				"reason":   reason,
				"ip":       ip,
			})

			s.kick(target, reason)

			exp := expIP
			if exp.IsZero() && !expName.IsZero() {
				exp = expName
			}
			if exp.IsZero() {
				return fmt.Sprintf("banned %s (permanent)", target.Name), nil
			}
			return fmt.Sprintf("banned %s until %s", target.Name, exp.UTC().Format(time.RFC3339)), nil
		},
	})

	reg.Register(Command{
		Name:        "unban",
		MinRole:     RoleAdmin,
		Usage:       `/unban ip:<addr>|name:<playername>`,
		Description: "Remove a ban entry",
		Handler: func(ctx context.Context, s *Server, actor *Client, args []string) (string, error) {
			if len(args) != 1 {
				return "", fmt.Errorf("usage: %s", `/unban ip:<addr>|name:<playername>`)
			}
			key := strings.TrimSpace(args[0])
			if !strings.HasPrefix(key, "ip:") && !strings.HasPrefix(key, "name:") {
				return "", errors.New("key must start with ip: or name:")
			}
			ok := s.removeBan(key)
			if !ok {
				return "", errors.New("ban entry not found")
			}
			return "unbanned " + key, nil
		},
	})

	reg.Register(Command{
		Name:        "giveitems",
		MinRole:     RoleAdmin,
		Usage:       `/giveitems <name|id> <item:qty> [item:qty ...]`,
		Description: "Give items to a player",
		Handler: func(ctx context.Context, s *Server, actor *Client, args []string) (string, error) {
			if len(args) < 2 {
				return "", fmt.Errorf("usage: %s", `/giveitems <name|id> <item:qty> [item:qty ...]`)
			}
			targetKey := args[0]
			itemArgs := args[1:]

			var target *Client
			var ok bool
			if len(targetKey) >= 8 {
				target, ok = s.getClientByID(targetKey)
			}
			if !ok {
				target, ok = s.getClientByName(targetKey)
			}
			if !ok {
				return "", fmt.Errorf("target not found: %s", targetKey)
			}

			items, err := parseGiveItemsArgs(itemArgs)
			if err != nil {
				return "", err
			}

			s.giveItems(target, items)
			cur := s.getItems(target)

			s.sendTo(target, map[string]any{
				"type":  "system",
				"event": "items_updated",
				"items": cur,
			})

			s.broadcast(nil, map[string]any{
				"type":   "system",
				"event":  "moderation",
				"action": "giveitems",
				"by":     actor.Name,
				"target": target.Name,
				"items":  items,
			})

			return fmt.Sprintf("gave items to %s", target.Name), nil
		},
	})

	reg.Register(Command{
		Name:        "items",
		MinRole:     RolePlayer,
		Usage:       `/items [name|id]`,
		Description: "Show your items (or another player's if admin)",
		Handler: func(ctx context.Context, s *Server, actor *Client, args []string) (string, error) {
			target := actor
			if len(args) == 1 {
				if !hasRole(actor.Role, RoleAdmin) {
					return "", errors.New("only admin can view other players' items")
				}
				key := args[0]
				var ok bool
				if len(key) >= 8 {
					target, ok = s.getClientByID(key)
				}
				if !ok {
					target, ok = s.getClientByName(key)
				}
				if !ok {
					return "", fmt.Errorf("target not found: %s", key)
				}
			} else if len(args) > 1 {
				return "", fmt.Errorf("usage: %s", `/items [name|id]`)
			}
			items := s.getItems(target)
			b, _ := json.Marshal(items)
			return fmt.Sprintf("%s items: %s", target.Name, string(b)), nil
		},
	})
}